class Character {
  int health = 100;
}

class Warrior extends Character {
  void attack() => print('Swings sword!');
}

class Mage extends Character {
  void castSpell() => print('Shoots fireball!');
}

void main() {
  Warrior w = Warrior();
  Mage m = Mage();

  // Both have health!
  print(w.health);
  print(m.health);
}
